mapper.select:
SELECT *
FROM music
WHERE mood_tag = #{mood}
ORDER BY play_count DESC, created_at DESC
LIMIT #{limit}

mapper.update:
UPDATE music
SET play_count = play_count + 1
WHERE id = #{id}

mapper.select:
SELECT * FROM music
(title LIKE CONCAT('%', #{kw}, '%') OR artist LIKE CONCAT('%', #{kw}, '%') OR album LIKE CONCAT('%', #{kw}, '%'))
ORDER BY updated_at DESC, id DESC LIMIT #{limit} OFFSET #{offset}
